<?phpheader("Content-Type: text/plain");//$excel ="<table>Ref. \t Date de la demande \t Délégué \t Prospects \t Secteur \t Type \t Date de la manifestation \t Lieu \t Budget demandé \t Budget investi \r\n";$excel ="<table border='1px'><tr><th>Ref.</th><th>Date de la demande</th><th>Type</th><th> Délégué</th><th>Prospects</th><th>Secteur</th><th>Date de la manifestation</th><th>Lieu</th> <th>Budget demandé</th><th>Budget investi</th><th>Produits</th></tr>";//Les resultats de la requette$where=array('public>='=>0);$de=filter_input(INPUT_GET,'de');$a=filter_input(INPUT_GET,'a');if($de)  $where['date >= ' ]=$de;if($a) $where['date <= ' ]=$a;$usr=filter_input(INPUT_GET,'user');if($usr)$where['id_user=']=$usr;$Liste  = get('*', 'demande',$where);$tab="\t";$ProdI="";foreach ($Liste['reponse'] as $demande):    $pro=$secteur=$ProdI="";    if($demande['prospects']) {        $ListePro = explode('_@_', $demande['prospects']);        $pros="";        foreach ($ListePro as $pro):            $pros.=  getinfo($pro,'prospect','Nom').' '.getinfo($pro,'prospect','Prenom').'<br/>';        endforeach;    }    $GouvInfo=  explode("@_@",$demande['secteur']);    foreach ($GouvInfo as $Gouv):        $secteur.= getinfo($Gouv,'gouvernerat','nom').' - ';    endforeach;    $Prod=get("*",'demande_prod',array('demande_id='=>$demande['id']));if($Prod['total']>0){    foreach ($Prod['reponse'] as $prod):        $ProdI.=' '.getinfo($prod['prod_id'],'products','name').' (Quantité : '.$prod['qte'].')<br/>';    endforeach;}$excel .="<tr><td>".getinfo(getinfo($demande['type'], 'type_demande', 'departement'), 'departement', 'abr').'/'.$demande['id'].'/'.date("Y", strtotime($demande['date']))."</td><td> $tab".$demande['created_at']."</td><td>".getinfo($demande['type'],'type_demande','name')."</td><td> ".getinfo($demande['id_user'] ,'users','Nom').' '.getinfo($demande['id_user'] ,'users','Prenom')."</td><td>".$pros."</td><td>".$secteur."</td><td>".$demande['date']."</td><td>".$demande['lieu']."</td> <td>".str_replace(".","," , $demande['budget_demander'])."TND</td><td>".str_replace(".","," ,$demande['budget_investi'])."TND</td><td>$ProdI</td></tr>";endforeach;$excel.="</table>";header('Content-type: application/vnd.ms-excel');header("Content-disposition: attachment; filename=Demande-$usr.xls");print $excel;exit;